const parts = msg.topic.split('/');
const floor = parts[2];
const room = parts[3];
const num = parseInt(room.substring(1), 10);
const localRoom = num % 100;
// CoAP = 1..10 per floor; MQTT = 11..20
const isCoap = localRoom >= 1 && localRoom <= 10;
if (isCoap) {
    msg.roomId = room;
    msg.floor = floor;
    msg.coapHost = env.get('COAP_HOST') || 'simulator';
    const floorNum = parseInt(floor.substring(1), 10);
    const roomsPerFloor = parseInt(env.get('ROOMS_PER_FLOOR') || '20', 10);
    const basePort = parseInt(env.get('COAP_BASE_PORT') || '5683', 10);
    const globalIndex = (floorNum - 1) * roomsPerFloor + (localRoom - 1);
    const reg = flow.get('coap_registry') || {};
    const key = `b01-${floor}-${room}`;
    if (reg[key] && reg[key].port != null) {
        msg.coapPort = reg[key].port;
        if (reg[key].host) { msg.coapHost = reg[key].host; }
    } else {
        msg.coapPort = basePort + globalIndex;
    }
    return [msg, null];
}
return [null, null];

const parts = msg.topic ? msg.topic.split('/') : [];
const room = msg.roomId || parts[3];
msg.topic = `campus/b01/f01/${room}/response`;
msg.qos = 2;
return msg;

if (!msg.payload) { return null; }
let data;
try { data = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload; }
catch (e) { node.warn('bad coap payload ' + e); return null; }
const roomId = data.room_id;
if (!roomId) { return null; }
msg.topic = `campus/b01/f01/${roomId.split('-')[2]}/telemetry`;
msg.payload = data;
msg.qos = 0;
// Cache last-seen telemetry for offline autonomy + floor summary.
const cache = flow.get('telemetry_cache') || {};
cache[roomId] = { data, ts: Date.now() };
flow.set('telemetry_cache', cache);
return msg;

const cache = flow.get('telemetry_cache') || {};
const rooms = Object.values(cache);
if (rooms.length === 0) { return null; }
let tSum = 0, hSum = 0, occ = 0;
for (const r of rooms) {
    tSum += r.data.temperature || 0;
    hSum += r.data.humidity || 0;
    if (r.data.occupancy) occ += 1;
}
msg.topic = `campus/b01/f01/floor_summary`;
msg.payload = {
    floor: 'f01',
    sample_count: rooms.length,
    avg_temperature: +(tSum / rooms.length).toFixed(2),
    avg_humidity: +(hSum / rooms.length).toFixed(2),
    occupied_rooms: occ,
    generated_at: Math.floor(Date.now() / 1000)
};
msg.qos = 1;
return msg;

// When HiveMQ is disconnected, iterate cached telemetry and push CoAP
// PUTs that turn lighting_dimmer=0 for rooms that are unoccupied. Messages
// are buffered in flow context for later replay on reconnect.
const status = msg.status && msg.status.text;
if (!status || !status.toLowerCase().includes('disconnected')) { return null; }
const cache = flow.get('telemetry_cache') || {};
const buffered = flow.get('buffered_summaries') || [];
const actions = [];
for (const [roomId, entry] of Object.entries(cache)) {
    if (entry.data.occupancy === false && (entry.data.lighting_dimmer || 0) > 0) {
        actions.push({
            topic: `campus/b01/f01/${roomId.split('-')[2]}/cmd`,
            payload: { action: 'set_dimmer', value: 0, command_id: `offline-${Date.now()}-${roomId}` }
        });
    }
}
buffered.push({ at: Date.now(), actions });
flow.set('buffered_summaries', buffered);
node.warn(`offline autonomy queued ${actions.length} actions`);
return null;
